1	/**
2	 * LayerInfinite MCP Server — config.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2 Gateway Configuration. Supports upstream MCP servers,
5	 * per-task-type mode overrides, shadow mode, and environment isolation.
6	 *
7	 * Backwards-compatible: all V1 env vars (LAYERINFINITE_API_KEY,
8	 * LAYERINFINITE_BASE_URL, LAYERINFINITE_MODE, LAYERINFINITE_ADMIN_KEY)
9	 * continue to work.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	export type LIMode = 'recommend' | 'assist' | 'auto';
14	
15	export interface ClassifierConfig {
16	  enabled: boolean;
17	  apiKey: string | null;
18	  model: string;
19	  baseUrl: string;
20	  timeoutMs: number;
21	  cacheTtlMs: number;
22	}
23	
24	export interface UpstreamServer {
25	  /** Human-readable name. Used as tool prefix (e.g. "github" → "github_push_fix"). */
26	  readonly name: string;
27	  /** MCP server URL (e.g., "https://github-mcp.example.com"). */
28	  readonly url: string;
29	  /** Optional per-upstream API key. Falls back to LAYERINFINITE_API_KEY if unset. */
30	  readonly apiKey?: string;
31	  /** Health check interval in ms. Default 30_000. */
32	  readonly healthCheckIntervalMs?: number;
33	}
34	
35	export interface GatewayConfig {
36	  /** API key for authenticating with the LayerInfinite REST API. */
37	  readonly apiKey: string;
38	  /** Base URL of the LayerInfinite API (no trailing slash). */
39	  readonly baseUrl: string;
40	  /** Global operating mode. null = bootstrap (observe only). */
41	  readonly mode: LIMode | null;
42	  /** Upstream MCP servers to proxy. */
43	  readonly upstreamServers: readonly UpstreamServer[];
44	  /** Per-task-type mode overrides. Key = task_type, value = mode. */
45	  readonly modeOverrides: ReadonlyMap<string, LIMode>;
46	  /** If true, LI observes and logs but does NOT inject enrichment. */
47	  readonly shadowMode: boolean;
48	  /** Deployment environment. Staging outcomes are isolated from production. */
49	  readonly environment: 'staging' | 'production';
50	  /** Admin key for gated operations. null = admin disabled. */
51	  readonly adminKey: string | null;
52	  /** Log level. Default derived from NODE_ENV. */
53	  readonly logLevel: 'debug' | 'info' | 'warn' | 'error';
54	  /** LLM outcome classifier config. null = classifier disabled. */
55	  readonly classifier: ClassifierConfig | null;
56	}
57	
58	const VALID_MODES: ReadonlySet<string> = new Set(['recommend', 'assist', 'auto']);
59	const VALID_ENVIRONMENTS: ReadonlySet<string> = new Set(['staging', 'production']);
60	
61	function parseUpstreamServers(raw: string): UpstreamServer[] {
62	  try {
63	    const parsed = JSON.parse(raw);
64	    if (!Array.isArray(parsed)) {
65	      throw new Error('LAYERINFINITE_UPSTREAM_TOOLS must be a JSON array');
66	    }
67	    return parsed.map((item: Record<string, unknown>, i: number) => {
68	      if (typeof item.name !== 'string' || item.name.trim() === '') {
69	        throw new Error(`Upstream server at index ${i}: "name" is required and must be a non-empty string`);
70	      }
71	      if (typeof item.url !== 'string' || item.url.trim() === '') {
72	        throw new Error(`Upstream server "${item.name}": "url" is required and must be a non-empty string`);
73	      }
74	      return {
75	        name: item.name.trim(),
76	        url: item.url.trim(),
77	        apiKey: typeof item.apiKey === 'string' ? item.apiKey : undefined,
78	        healthCheckIntervalMs: typeof item.healthCheckIntervalMs === 'number' ? item.healthCheckIntervalMs : undefined,
79	      };
80	    });
81	  } catch (err) {
82	    if (err instanceof SyntaxError) {
83	      throw new Error(`LAYERINFINITE_UPSTREAM_TOOLS is not valid JSON: ${err.message}`);
84	    }
85	    throw err;
86	  }
87	}
88	
89	function parseModeOverrides(raw: string): Map<string, LIMode> {
90	  if (!raw || raw.trim() === '' || raw.trim() === '{}') {
91	    return new Map();
92	  }
93	  try {
94	    const parsed = JSON.parse(raw);
95	    if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
96	      throw new Error('LAYERINFINITE_MODE_OVERRIDES must be a JSON object (e.g., {"build_failed":"auto"})');
97	    }
98	    const map = new Map<string, LIMode>();
99	    for (const [taskType, mode] of Object.entries(parsed)) {
100	      if (typeof mode !== 'string' || !VALID_MODES.has(mode)) {
101	        throw new Error(
102	          `LAYERINFINITE_MODE_OVERRIDES: invalid mode "${String(mode)}" for task "${taskType}". ` +
103	          `Valid values: recommend, assist, auto.`,
104	        );
105	      }
106	      map.set(taskType, mode as LIMode);
107	    }
108	    return map;
109	  } catch (err) {
110	    if (err instanceof SyntaxError) {
111	      throw new Error(`LAYERINFINITE_MODE_OVERRIDES is not valid JSON: ${err.message}`);
112	    }
113	    throw err;
114	  }
115	}
116	
117	/**
118	 * Reads and validates environment variables.
119	 * Throws immediately if required vars are missing — fail fast at startup.
120	 */
121	export function loadConfig(): GatewayConfig {
122	  // ── V1 backwards-compatible vars ──────────────────────────
123	  const apiKey = process.env.LAYERINFINITE_API_KEY;
124	  if (!apiKey || apiKey.trim() === '') {
125	    throw new Error(
126	      '[layerinfinite-mcp] LAYERINFINITE_API_KEY is required. ' +
127	      'Get your key from the LayerInfinite dashboard.',
128	    );
129	  }
130	
131	  const baseUrl = (process.env.LAYERINFINITE_BASE_URL ?? 'https://layerinfinite.me').replace(/\/+$/, '');
132	
133	  const rawMode = (process.env.LAYERINFINITE_MODE ?? '').trim().toLowerCase();
134	  let mode: LIMode | null = null;
135	  if (rawMode !== '') {
136	    if (!VALID_MODES.has(rawMode)) {
137	      throw new Error(
138	        `[layerinfinite-mcp] Invalid LAYERINFINITE_MODE="${rawMode}". ` +
139	        `Valid values: recommend, assist, auto. Omit for bootstrap mode.`,
140	      );
141	    }
142	    mode = rawMode as LIMode;
143	  }
144	
145	  const adminKey = process.env.LAYERINFINITE_ADMIN_KEY?.trim() || null;
146	
147	  // ── V2 new vars ──────────────────────────────────────────
148	  const rawUpstream = (process.env.LAYERINFINITE_UPSTREAM_TOOLS ?? '[]').trim();
149	  const upstreamServers = parseUpstreamServers(rawUpstream);
150	
151	  const rawOverrides = (process.env.LAYERINFINITE_MODE_OVERRIDES ?? '{}').trim();
152	  const modeOverrides = parseModeOverrides(rawOverrides);
153	
154	  const shadowMode = (process.env.LAYERINFINITE_SHADOW_MODE ?? 'false').trim().toLowerCase() === 'true';
155	
156	  const rawEnv = (process.env.LAYERINFINITE_ENVIRONMENT ?? 'production').trim().toLowerCase();
157	  if (!VALID_ENVIRONMENTS.has(rawEnv)) {
158	    throw new Error(
159	      `[layerinfinite-mcp] Invalid LAYERINFINITE_ENVIRONMENT="${rawEnv}". ` +
160	      `Valid values: staging, production.`,
161	    );
162	  }
163	  const environment = rawEnv as 'staging' | 'production';
164	
165	  const logLevel = resolveLogLevel();
166	
167	  // ── Classifier config ─────────────────────────────────────
168	  let classifier: ClassifierConfig | null = null;
169	  if ((process.env.LI_CLASSIFIER_ENABLED ?? '').toLowerCase() === 'true') {
170	    classifier = {
171	      enabled: true,
172	      apiKey: process.env.LI_CLASSIFIER_API_KEY ?? process.env.OPENAI_API_KEY ?? null,
173	      model: process.env.LI_CLASSIFIER_MODEL ?? 'gpt-4o-mini',
174	      baseUrl: (process.env.LI_CLASSIFIER_BASE_URL ?? 'https://api.openai.com/v1').replace(/\/+$/, ''),
175	      timeoutMs: Number.parseInt(process.env.LI_CLASSIFIER_TIMEOUT_MS ?? '3000', 10) || 3000,
176	      cacheTtlMs: Number.parseInt(process.env.LI_CLASSIFIER_CACHE_TTL_MS ?? '300000', 10) || 300000,
177	    };
178	  }
179	
180	  const config: GatewayConfig = Object.freeze({
181	    apiKey,
182	    baseUrl,
183	    mode,
184	    upstreamServers,
185	    modeOverrides,
186	    shadowMode,
187	    environment,
188	    adminKey,
189	    logLevel,
190	    classifier,
191	  });
192	
193	  return config;
194	}
195	
196	function resolveLogLevel(): GatewayConfig['logLevel'] {
197	  const raw = (process.env.LAYERINFINITE_LOG_LEVEL ?? '').trim().toLowerCase();
198	  if (['debug', 'info', 'warn', 'error'].includes(raw)) {
199	    return raw as GatewayConfig['logLevel'];
200	  }
201	  // Derive from NODE_ENV
202	  if (process.env.NODE_ENV === 'production') return 'info';
203	  if (process.env.NODE_ENV === 'test') return 'error';
204	  return 'debug';
205	}
