1	#!/usr/bin/env node
2	
3	/**
4	 * LayerInfinite MCP Server — bin/cli.ts
5	 * ══════════════════════════════════════════════════════════════
6	 * Entry point for stdio transport. This is what Claude Desktop,
7	 * Cursor, Cline, and other MCP hosts spawn as a child process.
8	 *
9	 * Usage:
10	 *   LAYERINFINITE_API_KEY=xxx npx layerinfinite-mcp
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
15	import { createGatewayServer } from '../src/index.js';
16	import { logger } from '../src/logger.js';
17	
18	const log = logger.forTool('cli');
19	
20	let shuttingDown = false;
21	
22	async function main() {
23	  log.info('LayerInfinite Gateway starting', { version: '2.0.0' });
24	
25	  const gateway = createGatewayServer();
26	  const { server, proxy, upstreamClient, registry, tracker, queueProcessor } = gateway;
27	
28	  // Start upstream health checks
29	  upstreamClient.startHealthChecks();
30	
31	  const transport = new StdioServerTransport();
32	
33	  async function shutdown(signal: string) {
34	    if (shuttingDown) return;
35	    shuttingDown = true;
36	    log.info('Shutting down', { signal });
37	
38	    try {
39	      registry.stopHealthChecks();
40	      queueProcessor.stop();
41	      tracker.stopFlushTimer();
42	      await tracker.flushBuffer();
43	      await proxy.shutdown();
44	      await server.close();
45	      log.info('Server closed cleanly');
46	    } catch (err) {
47	      log.error('Error during shutdown', {
48	        error: err instanceof Error ? err.message : String(err),
49	      });
50	    }
51	
52	    process.exit(0);
53	  }
54	
55	  process.on('SIGINT', () => shutdown('SIGINT'));
56	  process.on('SIGTERM', () => shutdown('SIGTERM'));
57	  process.on('unhandledRejection', (reason) => {
58	    log.error('Unhandled rejection', {
59	      error: reason instanceof Error ? reason.message : String(reason),
60	      stack: reason instanceof Error ? reason.stack : undefined,
61	    });
62	  });
63	
64	  await server.connect(transport);
65	  log.info('Gateway connected via stdio', {
66	    mode: gateway.config.mode ?? 'bootstrap',
67	    upstreams: gateway.config.upstreamServers.length,
68	  });
69	}
70	
71	main().catch((err) => {
72	  log.error('Fatal startup error', {
73	    error: err instanceof Error ? err.message : String(err),
74	    stack: err instanceof Error ? err.stack : undefined,
75	  });
76	  process.exit(1);
77	});
